def build_restart_args() -> list[str]:
    """Build execv args for restarting the dashboard.

    Always uses ``-m claude_dashboard`` to avoid adding the package directory
    to sys.path (which would shadow stdlib ``platform`` with
    ``claude_dashboard/platform``).
    """
    return [sys.executable, "-m", "claude_dashboard"] + sys.argv[1:]


class _SessionEntry:
    """Tracks a live session: its info, container, and current state."""

    __slots__ = (
        "session",
        "container",
        "state",
        "hidden",
        "branch",
        "flagged",
        "git_status",
        "merged",
        "agents",
        "unattached",
    )

    def __init__(self, session: SessionInfo):
        self.session = session
        self.container: ContainerInfo | None = None
        self.state: StatusState = StatusState.IDLE
        self.hidden: bool = False
        self.branch: str = ""
        self.flagged: bool = False
        self.git_status: GitStatus = GitStatus.CLEAN
        self.merged: bool = False
        self.agents: dict[str, _AgentEntry] = {}
        self.unattached: bool = False

    @property
    def effective_state(self) -> StatusState:
        """Highest-priority state across main process + all agents."""
        best = self.state
        best_p = _STATE_PRIORITY.get(best, 999)
        for agent in self.agents.values():
            p = _STATE_PRIORITY.get(agent.state, 999)
            if p < best_p:
                best = agent.state
                best_p = p
        return best


def write_vscode_tasks_json(*, cwd: str) -> None:
    """Write the VS Code tasks.json template to <cwd>/.vscode/tasks.json.

    Skips if the file already exists (whether ours or user-modified).
    The file is kept permanently and globally gitignored.
    """
    cwd_path = Path(cwd)
    if not cwd_path.is_dir():
        logger.warning("cwd does not exist, skipping tasks.json write cwd=%s", cwd)
        return

    tasks_path = cwd_path / ".vscode" / "tasks.json"
    if tasks_path.exists():
        logger.debug("tasks.json already exists cwd=%s", cwd)
        return

    tasks_path.parent.mkdir(parents=True, exist_ok=True)
    tasks_path.write_text(config.VSCODE_TASKS_JSON_TEMPLATE, encoding="utf-8")
    logger.info("wrote tasks.json cwd=%s", cwd)


