    def _discovery_tick(self):
        """Discover new sessions and remove dead ones.

        Flow: discover → register new → ghost dead → prune deleted CWDs →
        git status (all sessions) → refresh UI.
        """
        try:
            discovered = discover_sessions()
            alive_pids = set()

            # 1. Register new live sessions
            for session in discovered:
                if not validate_pid(pid=session.pid):
                    continue
                session.pid_alive = True
                alive_pids.add(session.pid)
                if session.pid not in self._sessions:
                    self._add_session(session)

            # 2. Convert dead sessions to ghosts
            dead_pids = set(self._sessions.keys()) - alive_pids
            for pid in dead_pids:
                entry = self._sessions.get(pid)
                if entry and not entry.unattached:
                    cwd = entry.session.cwd
                    flagged = entry.flagged
                    self._remove_session(pid)
                    self._create_ghost(cwd=cwd, flagged=flagged)

            # 3. On first tick, create unattached placeholders from state file
            if not self._first_tick_done:
                self._create_unattached_from_state(alive_pids)

            # 4. Prune ghosts whose CWD no longer exists
            stale_pids = [
                pid
                for pid, entry in self._sessions.items()
                if entry.unattached and not Path(entry.session.cwd).is_dir()
            ]
            for pid in stale_pids:
                cwd = self._sessions[pid].session.cwd
                self._sessions.pop(pid, None)
                logger.info("pruned ghost for deleted directory %s", cwd)

            # 5. Update git state for all sessions.
            # Live: git_check every tick, fetch every ~60s.
            # Ghosts: both every ~5 min.
            self._fetch_tick_counter += 1
            fetch_tick = self._fetch_tick_counter >= self._fetch_tick_interval
            if fetch_tick:
                self._fetch_tick_counter = 0
            self._ghost_git_tick_counter += 1
            ghost_tick = self._ghost_git_tick_counter >= self._ghost_git_tick_interval
            if ghost_tick:
                self._ghost_git_tick_counter = 0

            fetched_cwds: set[str] = set()
            for entry in self._sessions.values():
                is_ghost = entry.unattached
                if is_ghost and not ghost_tick:
                    continue

                cwd = entry.session.cwd

                # Fetch remote refs on the appropriate tick (deduplicated by CWD)
                should_fetch = ghost_tick if is_ghost else fetch_tick
                if (
                    should_fetch
                    and entry.git_status == config.GitStatus.PUSHED_NOT_MERGED
                    and cwd not in fetched_cwds
                ):
                    fetched_cwds.add(cwd)
                    if cwd not in self._trunk_cache:
                        self._populate_trunk_cache(cwd)
                    remote = self._trunk_cache[cwd].get("remote", "")
                    if remote:
                        try:
                            subprocess.run(
                                ["git", "fetch", remote],
                                cwd=cwd,
                                stdout=subprocess.DEVNULL,
                                stderr=subprocess.DEVNULL,
                                timeout=10,
                                creationflags=config.SUBPROCESS_FLAGS,
                            )
                        except (OSError, subprocess.TimeoutExpired):
                            pass

                # Update branch, git status, and merge status
                trunk_branch = self._trunk_branch(cwd)
                entry.branch = detect_branch(cwd=cwd, trunk_branch=trunk_branch)
                trunk_ref = self._trunk_ref(cwd)
                start = time.monotonic()
                new_git_status, new_merged = git_check(
                    cwd=cwd, trunk_ref=trunk_ref, branch=entry.branch
                )
                elapsed = time.monotonic() - start
                if elapsed <= 0.5:
                    entry.git_status = new_git_status
                    entry.merged = new_merged

            if fetched_cwds:
                # Clear trunk cache after fetch so newly-added remotes are detected
                self._trunk_cache.clear()

            now = time.monotonic()
            if now - self._daily_cost_last_read >= self._settings.poll_interval_seconds * 10:
                self._daily_cost = read_daily_cost()
                self._daily_cost_last_read = now
            self._usage_limits = read_usage_limits()

            # Refresh UI (state may not have changed, but rows may have been added/removed)
            self._refresh_ui()
            self._first_tick_done = True

        except Exception as exc:
            logger.error("discovery tick failed error=%s", exc)

        tick_ms = self._settings.poll_interval_seconds * 1000
        self._root.after(tick_ms, self._discovery_tick)

    # ------------------------------------------------------------------
    # Session lifecycle
    # ------------------------------------------------------------------

    def _populate_trunk_cache(self, cwd: str) -> None:
        """Populate trunk cache for a CWD using file reads (no subprocess)."""
        remote, trunk_ref, trunk_branch = read_trunk_info(cwd=cwd)
        self._trunk_cache[cwd] = {
            "branch": trunk_branch,
            "ref": trunk_ref,
            "remote": remote,
        }

    def _trunk_branch(self, cwd: str) -> str:
        """Return cached trunk branch name for a CWD, populating on first access."""
        if cwd not in self._trunk_cache:
            self._populate_trunk_cache(cwd)
        return self._trunk_cache[cwd].get("branch", "")

    def _trunk_ref(self, cwd: str) -> str:
        """Return cached trunk ref (e.g. 'origin/main') for a CWD."""
        if cwd not in self._trunk_cache:
            self._populate_trunk_cache(cwd)
        return self._trunk_cache[cwd].get("ref", "")

    def _is_ignored(self, cwd: str) -> bool:
        """Check if a CWD matches the ignore regex setting."""
        regex = self._settings.ignore_regex
        if not regex:
            return False
        try:
            return bool(re.match(regex, cwd))
        except re.error:
            return False

    def _add_session(self, session: SessionInfo):
        if self._is_ignored(session.cwd):
            logger.debug("pid=%d ignored (cwd=%s matches ignore_regex)", session.pid, session.cwd)
            return
        entry = _SessionEntry(session)
        # All new sessions start as IDLE until a hook event updates them.
        entry.container = detect_container(session.pid)
        entry.container = find_window_for_session(session.cwd, entry.container)
        trunk_branch = self._trunk_branch(session.cwd)
        entry.branch = detect_branch(cwd=session.cwd, trunk_branch=trunk_branch)
        trunk_ref = self._trunk_ref(session.cwd)
        start = time.monotonic()
        entry.git_status, entry.merged = git_check(
            cwd=session.cwd, trunk_ref=trunk_ref, branch=entry.branch
        )
        elapsed = time.monotonic() - start
        if elapsed > 0.5:
            logger.warning(
                "pid=%d git check took %.1fs on first detection",
                session.pid,
                elapsed,
            )

        # Replace unattached placeholder if one exists for this CWD
        unattached_pid = self._find_unattached_pid(session.cwd)
        if unattached_pid is not None:
            old = self._sessions.pop(unattached_pid, None)
            if old:
                entry.flagged = old.flagged
                # Live session replaces ghost — always unhide so it's visible
                entry.hidden = False
                logger.debug(
                    "pid=%d replaced unattached placeholder for %s", session.pid, session.cwd
                )
        else:
            self._apply_saved_state(entry)

        # Auto-hide non-interactive sessions (e.g. claude -p)
        if session.entrypoint != "cli":
            entry.hidden = True
            logger.info("pid=%d auto-hidden (entrypoint=%s)", session.pid, session.entrypoint)

        self._sessions[session.pid] = entry
        self._session_id_to_pid[session.session_id] = session.pid

        # Replay any buffered hook state (overrides saved state)
        buffered = self._pending_hook_states.pop(session.session_id, None)
        if buffered is not None:
            entry.state = buffered

        cwd_short = cwd_basename(cwd=session.cwd)
        logger.debug(
            "pid=%d project=%s new_state=%s prior_state=None",
            session.pid,
            cwd_short,
            entry.state.value,
        )

    def _find_unattached_pid(self, cwd: str) -> int | None:
        """Find an unattached placeholder PID for the given CWD."""
        for pid, entry in self._sessions.items():
            if entry.unattached and entry.session.cwd == cwd:
                return pid
        return None

    def _create_unattached_from_state(self, alive_pids: set[int]):
        """Create ghost entries from state file for CWDs without live sessions."""
        live_cwds = {e.session.cwd for e in self._sessions.values()}
        for cwd, saved in self._saved_state.items():
            if cwd in live_cwds:
                continue
            if self._is_ignored(cwd):
                continue
            self._next_synthetic_pid -= 1
            synthetic_pid = self._next_synthetic_pid
            session = SessionInfo(
                pid=synthetic_pid,
                session_id=f"unattached-{synthetic_pid}",
                cwd=cwd,
                started_at=0,
                pid_alive=False,
            )
            entry = _SessionEntry(session)
            entry.unattached = True
            if saved.get("flagged"):
                entry.flagged = True
            if saved.get("hidden"):
                entry.hidden = True
            entry.branch = detect_branch(cwd=cwd, trunk_branch=self._trunk_branch(cwd))
            trunk_ref = self._trunk_ref(cwd)
            entry.git_status, entry.merged = git_check(
                cwd=cwd, trunk_ref=trunk_ref, branch=entry.branch
            )
            self._sessions[synthetic_pid] = entry
            logger.debug("created unattached placeholder for %s pid=%d", cwd, synthetic_pid)

    def _create_ghost(self, *, cwd: str, flagged: bool = False):
        """Create an unattached ghost for a CWD if no live session or ghost exists for it."""
        # Skip if another live session still uses this CWD
        for entry in self._sessions.values():
            if entry.session.cwd == cwd:
                logger.debug("skip ghost for %s — session still exists", cwd)
                return
        self._next_synthetic_pid -= 1
        synthetic_pid = self._next_synthetic_pid
        session = SessionInfo(
            pid=synthetic_pid,
            session_id=f"unattached-{synthetic_pid}",
            cwd=cwd,
            started_at=0,
            pid_alive=False,
        )
        entry = _SessionEntry(session)
        entry.unattached = True
        entry.flagged = flagged
        entry.branch = detect_branch(cwd=cwd, trunk_branch=self._trunk_branch(cwd))
        trunk_ref = self._trunk_ref(cwd)
        entry.git_status, entry.merged = git_check(
            cwd=cwd, trunk_ref=trunk_ref, branch=entry.branch
        )
        self._sessions[synthetic_pid] = entry
        logger.info("created ghost for %s pid=%d", cwd, synthetic_pid)

    def _remove_session(self, pid: int):
        entry = self._sessions.pop(pid, None)
        if entry:
            self._session_id_to_pid.pop(entry.session.session_id, None)
            logger.debug("session gone pid=%d", pid)

    # ------------------------------------------------------------------
    # Hook event callback (fired from HTTP server thread)
    # ------------------------------------------------------------------

    def _on_hook_event(
        self,
        session_id: str,
        event: str,
        new_state: StatusState,
        cwd: str = "",
        agent_id: str = "",
        agent_type: str = "",
    ) -> None:
        """Called from hook server thread. Marshal to main thread."""
        self._root.after(
            0,
            self._apply_hook_state,
            session_id,
            event,
            new_state,
            cwd,
            agent_id,
            agent_type,
        )

    def _on_hook_session_end(self, session_id: str):
        """Called from hook server thread on SessionEnd."""
        self._root.after(0, self._handle_session_end, session_id)

    def _on_hook_agent_stop(self, session_id: str, agent_id: str):
        """Called from hook server thread on SubagentStop."""
        self._root.after(0, self._handle_agent_stop, session_id, agent_id)

    def _apply_hook_state(
        self,
        session_id: str,
        event: str,
        new_state: StatusState,
        cwd: str = "",
        agent_id: str = "",
        agent_type: str = "",
    ):
        """Apply a hook-driven state change on the main thread."""
        pid = self._session_id_to_pid.get(session_id)

        # Fallback: match by CWD if session_id not found (resumed sessions
        # may have a different session_id than what's in sessions/*.json)
        if pid is None and cwd:
            for candidate in self._sessions.values():
                if candidate.session.cwd == cwd:
                    pid = candidate.session.pid
                    # Register this session_id for future lookups
                    self._session_id_to_pid[session_id] = pid
                    break

        if pid is None:
            # Buffer — session not yet discovered
            self._pending_hook_states[session_id] = new_state
            return

        entry = self._sessions.get(pid)
        if not entry:
            return

        if agent_id:
            # Agent event — register or update agent
            agent = entry.agents.get(agent_id)
            if agent is None:
                agent = _AgentEntry(
                    agent_id=agent_id,
                    state=new_state,
                    agent_type=agent_type,
                )
                entry.agents[agent_id] = agent
                logger.debug(
                    "pid=%d agent=%s registered state=%s",
                    pid,
                    agent_id[:12],
                    new_state.value,
                )
            else:
                agent.state = new_state

            # Debounce agent permission requests by 5s — agents are typically
            # run via skills that auto-resolve permission prompts. Only surface
            # in the UI if the permission is still pending after the delay.
            if new_state == StatusState.PERMISSION_REQUIRED:
                pending = self._agent_perm_debounce.pop(agent_id, None)
                if pending is not None:
                    self._root.after_cancel(pending)
                self._agent_perm_debounce[agent_id] = self._root.after(
                    5000, self._flush_agent_perm_debounce, agent_id
                )
                return
            # Non-permission event clears any pending debounce for this agent
            pending = self._agent_perm_debounce.pop(agent_id, None)
            if pending is not None:
                self._root.after_cancel(pending)
            self._refresh_ui()
            return

        # Main process event
        # Note: we do NOT clear agents on UserPromptSubmit because auto-wake
        # events (fired after each SubagentStop) are indistinguishable from
        # real user prompts and would prematurely clear active agents.
        # Agents are removed individually via SubagentStop or on PID death.

        prior = entry.state

        # Intercept idle: transition to ready instead (cleared by row click)
        if new_state == StatusState.IDLE:
            new_state = StatusState.READY

        if prior == new_state:
            return

        # Don't let parallel tool failures overwrite a pending permission.
        # When Claude fires parallel tool calls, one may need permission while
        # others fail. PostToolUseFailure should not clear permission_required.
        # PostToolUse is allowed (permission was auto-resolved or granted).
        if (
            prior == StatusState.PERMISSION_REQUIRED
            and new_state == StatusState.WORKING
            and event == "PostToolUseFailure"
        ):
            logger.debug(
                "pid=%d ignoring PostToolUseFailure during permission_required",
                pid,
            )
            return

        entry.state = new_state
        entry.branch = detect_branch(
            cwd=entry.session.cwd, trunk_branch=self._trunk_branch(entry.session.cwd)
        )
        cwd_short = cwd_basename(cwd=entry.session.cwd)
        logger.debug(
            "pid=%d project=%s new_state=%s prior_state=%s event=%s",
            pid,
            cwd_short,
            new_state.value,
            prior.value,
            event,
        )
        self._refresh_ui()

    def _flush_agent_perm_debounce(self, agent_id: str):
        """Debounce timer expired — agent permission is still pending, show it."""
        self._agent_perm_debounce.pop(agent_id, None)
        self._refresh_ui()

    def _handle_agent_stop(self, session_id: str, agent_id: str):
        """Remove an agent from a session."""
        # Cancel any pending permission debounce for this agent
        pending = self._agent_perm_debounce.pop(agent_id, None)
        if pending is not None:
            self._root.after_cancel(pending)
        pid = self._session_id_to_pid.get(session_id)
        if pid is None:
            return
        entry = self._sessions.get(pid)
        if not entry:
            return
        removed = entry.agents.pop(agent_id, None)
        if removed:
            logger.debug(
                "pid=%d agent=%s removed, %d agents remain",
                pid,
                agent_id[:12],
                len(entry.agents),
            )
            self._refresh_ui()

    def _handle_session_end(self, session_id: str):
        """Handle SessionEnd hook — convert to ghost."""
        pid = self._session_id_to_pid.get(session_id)
        if pid is not None:
            entry = self._sessions.get(pid)
            if entry and not entry.unattached:
                cwd = entry.session.cwd
                flagged = entry.flagged
                self._remove_session(pid)
                self._create_ghost(cwd=cwd, flagged=flagged)
            self._refresh_ui()

    # ------------------------------------------------------------------
    # UI refresh
    # ------------------------------------------------------------------

    def _sorted_entries(self) -> list["_SessionEntry"]:
        """Return all session entries sorted by display name."""
        return sorted(
            self._sessions.values(),
            key=lambda e: cwd_relative_to_home(cwd=e.session.cwd).lower(),
        )

    def _refresh_ui(self):
        """Debounced UI refresh. High-priority states bypass debounce (FR-043)."""
        all_entries = self._sorted_entries()
        bypass = any(
            entry.effective_state in (StatusState.PERMISSION_REQUIRED, StatusState.AWAITING_INPUT)
            for entry in all_entries
            if not entry.hidden
        )

        if bypass:
            if self._debounce_id is not None:
                self._root.after_cancel(self._debounce_id)
                self._debounce_id = None
            logger.debug("refresh_ui: bypass (immediate)")
            self._do_refresh_ui(all_entries)
        else:
            had_pending = self._debounce_id is not None
            if had_pending:
                self._root.after_cancel(self._debounce_id)
            self._debounce_id = self._root.after(
                _DEBOUNCE_MS,
                self._do_refresh_ui_deferred,
            )
            logger.debug(
                "refresh_ui: debounce %dms (cancelled_pending=%s)",
                _DEBOUNCE_MS,
                had_pending,
            )

    def _do_refresh_ui_deferred(self):
        """Called by debounce timer — re-reads current state to avoid staleness."""
        self._debounce_id = None
        self._do_refresh_ui(self._sorted_entries())

    def _do_refresh_ui(self, all_entries: list["_SessionEntry"]):
        """Actual UI refresh logic."""
        visible_states = [
            SessionRow(
                session=entry.session,
                state=entry.effective_state,
                container=entry.container,
                branch=entry.branch,
                flagged=entry.flagged,
                git_status=entry.git_status,
                merged=entry.merged,
                agent_count=len(entry.agents),
                unattached=entry.unattached,
            )
            for entry in all_entries
            if not entry.hidden
        ]
        self._main_window.update_sessions(visible_states)

        highest = self._highest_priority_state(visible_states)
        if highest != self._tray_state:
            self._tray_state = highest
            update_tray_icon(self._tray_icon, color=self._tray_color_for_state(highest))

        active = sum(1 for e in all_entries if not e.hidden and not e.unattached)
        hidden_live = sum(1 for e in all_entries if e.hidden and not e.unattached)
        hidden_ghost = sum(1 for e in all_entries if e.hidden and e.unattached)
        self._main_window.update_title_bar(
            daily_cost=self._daily_cost,
            limits=self._usage_limits,
            active=active,
            hidden_live=hidden_live,
            hidden_ghost=hidden_ghost,
            highest_state_color=self._tray_color_hex_for_state(highest),
        )

        self._save_session_state()

    # ------------------------------------------------------------------
    # Row click
    # ------------------------------------------------------------------

    def _on_row_left_click(self, session: SessionInfo):
        logger.info("row clicked pid=%d cwd=%s", session.pid, session.cwd)
        entry = self._sessions.get(session.pid)

        # Unattached sessions open in VS Code on left-click
        if entry and entry.unattached:
            self._open_in_vscode(cwd=session.cwd)
            return

        container = entry.container if entry else None

        # Clicking a Ready session clears to Idle
        if entry and entry.state == StatusState.READY:
            entry.state = StatusState.IDLE
            logger.debug("pid=%d clicked, cleared ready to idle", session.pid)
            self._refresh_ui()

        if not container:
            container = detect_container(session.pid)
            container = find_window_for_session(session.cwd, container)
            if entry:
                entry.container = container

        if container and (container.window_handle or container.process_pid):
            success = foreground_window(container, cwd=session.cwd)
            if not success:
                logger.warning("failed to foreground pid=%d", session.pid)

    def _on_row_double_click(self, session: SessionInfo):
        """Double-click opens PR if branch is pushed-not-merged."""
        entry = self._sessions.get(session.pid)
        if entry and entry.git_status == config.GitStatus.PUSHED_NOT_MERGED:
            self._open_pr(session)
            return

    def _on_row_middle_click(self, session: SessionInfo):
        """Middle-click toggles flagged state."""
        entry = self._sessions.get(session.pid)
        if entry:
            entry.flagged = not entry.flagged
            logger.debug("pid=%d flagged=%s", session.pid, entry.flagged)
            self._refresh_ui()

    def _on_row_right_click(self, session: SessionInfo, x: int, y: int):
        """Per-row right-click: ghost gets Dismiss/Open, live gets Hide/Clear State."""
        entry = self._sessions.get(session.pid)
        if entry and entry.unattached:
            self._show_ghost_context_menu(session, x, y)
        else:
            self._show_live_context_menu(session, x, y)

    def _show_live_context_menu(self, session: SessionInfo, x: int, y: int):
        """Show context menu for live sessions: Hide, Clear State."""
        if self._context_menu_open:
            self._context_menu.unpost()
            self._context_menu_open = False
            return
        self._context_menu.unpost()
        self._context_menu.delete(0, tk.END)

        entry = self._sessions.get(session.pid)
        if not entry:
            return

        cwd_display = cwd_relative_to_home(cwd=session.cwd)

        def hide():
            entry.hidden = True
            logger.info("pid=%d hidden via context menu", session.pid)
            self._save_session_state()
            self._refresh_ui()

        def clear_state():
            entry.state = StatusState.IDLE
            entry.agents.clear()
            logger.info("pid=%d state cleared via context menu", session.pid)
            self._refresh_ui()

        self._context_menu.add_command(label=cwd_display, state=tk.DISABLED)
        self._context_menu.add_separator()
        if entry.git_status == config.GitStatus.PUSHED_NOT_MERGED:
            self._context_menu.add_command(
                label="Open PR",
                command=lambda: self._open_pr(session),
            )
        self._context_menu.add_command(label="Hide", command=hide)
        self._context_menu.add_command(label="Clear State", command=clear_state)

        self._context_menu_open = True
        popup_menu_clamped(self._context_menu, x=x, y=y)

    def _show_ghost_context_menu(self, session: SessionInfo, x: int, y: int):
        """Show context menu for ghost (unattached) sessions."""
        if self._context_menu_open:
            self._context_menu.unpost()
            self._context_menu_open = False
            return
        self._context_menu.unpost()
        self._context_menu.delete(0, tk.END)

        cwd_display = cwd_relative_to_home(cwd=session.cwd)

        def dismiss():
            self._sessions.pop(session.pid, None)
            logger.info("pid=%d ghost dismissed via context menu", session.pid)
            self._refresh_ui()

        def open_in_vscode():
            self._open_in_vscode(cwd=session.cwd)

        def hide():
            entry = self._sessions.get(session.pid)
            if entry:
                entry.hidden = True
                logger.info("pid=%d ghost hidden via context menu", session.pid)
                self._save_session_state()
                self._refresh_ui()

        self._context_menu.add_command(label=f"Ghost: {cwd_display}", state=tk.DISABLED)
        self._context_menu.add_separator()
        entry = self._sessions.get(session.pid)
        if entry and entry.git_status == config.GitStatus.PUSHED_NOT_MERGED:
            self._context_menu.add_command(
                label="Open PR",
                command=lambda: self._open_pr(session),
            )
        self._context_menu.add_command(label="Open in VS Code", command=open_in_vscode)
        self._context_menu.add_command(label="Hide", command=hide)
        self._context_menu.add_command(label="Dismiss", command=dismiss)

        self._context_menu_open = True
        popup_menu_clamped(self._context_menu, x=x, y=y)

    def _launch_vscode(self, *, folder: str):
        """Launch VS Code for the given folder."""
        code_path = shutil.which("code")
        if not code_path:
            logger.warning(
                "VS Code 'code' command not found — install it via "
                "Command Palette > Shell Command: Install 'code' command in PATH"
            )
            return
        try:
            subprocess.Popen(
                [code_path, folder],
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                creationflags=config.SUBPROCESS_FLAGS,
            )
            logger.info("launched VS Code for folder=%s", folder)
        except OSError as exc:
            logger.warning("failed to launch VS Code for folder=%s error=%s", folder, exc)

    def _open_in_vscode(self, *, cwd: str):
        """Write tasks.json and launch VS Code for a directory."""
        write_vscode_tasks_json(cwd=cwd)
        self._launch_vscode(folder=cwd)

    def _open_folder(self):
        """Show a folder picker and open the selected folder in VS Code."""
        folder = filedialog.askdirectory(title="Open folder in VS Code")
        if not folder:
            return
        self._open_in_vscode(cwd=folder)

    def _open_pr(self, session: SessionInfo):
        """Open the GitHub PR for the session's branch, or create-PR page if none exists."""
        try:
            result = subprocess.run(
                ["gh", "pr", "view", "--web"],
                cwd=session.cwd,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                timeout=10,
                creationflags=config.SUBPROCESS_FLAGS,
            )
            if result.returncode == 0:
                logger.info("opened PR in browser for cwd=%s", session.cwd)
            else:
                subprocess.Popen(
                    ["gh", "pr", "create", "--web"],
                    cwd=session.cwd,
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.DEVNULL,
                    creationflags=config.SUBPROCESS_FLAGS,
                )
                logger.info("no PR found, opened create-PR page for cwd=%s", session.cwd)
        except FileNotFoundError:
            logger.warning("gh CLI not found — install from https://cli.github.com/")
        except subprocess.TimeoutExpired:
            logger.warning("gh pr view timed out for cwd=%s", session.cwd)
        except OSError as exc:
            logger.warning("failed to open PR for cwd=%s error=%s", session.cwd, exc)

    def _on_ghost_toggle(self, *, force_show: bool = False):
        """Middle-click on title bar — toggle ghost session visibility.

        If force_show is True, always show ghosts (used when unshading).
        Otherwise: if any non-flagged ghosts are visible, hide them.
        Flagged ghosts are never hidden by this toggle.
        """
        if force_show:
            hide = False
        else:
            any_visible = any(
                entry.unattached and not entry.hidden and not entry.flagged
                for entry in self._sessions.values()
            )
            hide = any_visible
        for entry in self._sessions.values():
            if entry.unattached and not entry.flagged:
                entry.hidden = hide
        self._ghosts_hidden = hide
        logger.info("ghosts %s via title bar", "hidden" if hide else "shown")
        self._save_session_state()
        self._refresh_ui()

    def _on_cost_click(self, x: int, y: int):
        """Left-click on cost/usage labels — show cost history popup."""
        popup = CostPopup(self._root, anchor_x=x, anchor_y=y)
        self._main_window._cost_popup = popup

    def _clear_agents(self, session: SessionInfo):
        """Clear all agents from a session (manual reset for stale agent state)."""
        entry = self._sessions.get(session.pid)
        if entry and entry.agents:
            entry.agents.clear()
            logger.info("pid=%d agents cleared", session.pid)
            self._refresh_ui()

    # ------------------------------------------------------------------
    # Session visibility menu
    # ------------------------------------------------------------------

    def _build_sessions_menu(self, menu: tk.Menu):
        """Populate a menu with session visibility checkboxes (live sessions only)."""
        self._session_vars.clear()
        all_entries = self._sorted_entries()
        for entry in all_entries:
            if entry.unattached:
                continue
            var = tk.BooleanVar(value=not entry.hidden)
            self._session_vars.append(var)
            display_name = cwd_relative_to_home(cwd=entry.session.cwd)

            def make_toggle(e=entry, v=var):
                def toggle():
                    e.hidden = not v.get()
                    self._save_session_state()
                    self._refresh_ui()

                return toggle

            menu.add_checkbutton(
                label=display_name,
                variable=var,
                command=make_toggle(),
            )

    def _on_right_click(self, x: int, y: int):
        """Window-level right-click on empty areas — show sessions visibility menu."""
        if self._context_menu_open:
            self._context_menu.unpost()
            self._context_menu_open = False
            return
        self._context_menu.unpost()
        self._context_menu.delete(0, tk.END)

        self._build_sessions_menu(self._context_menu)

        self._context_menu_open = True
        popup_menu_clamped(self._context_menu, x=x, y=y)

    # ------------------------------------------------------------------
    # Session state persistence (restart continuity)
    # ------------------------------------------------------------------

    def _load_session_state(self) -> dict[str, dict]:
        """Load saved session state keyed by CWD."""
        try:
            data = json.loads(config.STATE_FILE.read_text(encoding="utf-8"))
            if isinstance(data, dict):
                return data
        except (FileNotFoundError, json.JSONDecodeError, OSError):
            pass
        return {}

    def _save_session_state(self):
        """Snapshot mutable session state to disk."""
        state: dict[str, dict] = {}
        for entry in self._sessions.values():
            cwd = entry.session.cwd
            if self._is_ignored(cwd):
                continue
            agents = {
                aid: {"state": a.state.value, "agent_type": a.agent_type}
                for aid, a in entry.agents.items()
            }
            if cwd in state:
                # Multiple sessions share this CWD — only hide if ALL are hidden
                if not entry.hidden:
                    state[cwd]["hidden"] = False
                # Merge agents and prefer highest-priority state
                state[cwd]["agents"].update(agents)
            else:
                state[cwd] = {
                    "state": entry.state.value,
                    "hidden": entry.hidden,
                    "flagged": entry.flagged,
                    "agents": agents,
                }

        try:
            atomic_write_json(data=state, path=config.STATE_FILE)
        except OSError as exc:
            logger.debug("failed to save session state error=%s", exc)

    def _apply_saved_state(self, entry: "_SessionEntry"):
        """Apply saved state from a previous run to a newly discovered session."""
        saved = self._saved_state.get(entry.session.cwd)
        if not saved:
            return
        if saved.get("flagged"):
            entry.flagged = True
        if saved.get("hidden"):
            entry.hidden = True
        state_val = saved.get("state")
        if state_val:
            try:
                entry.state = StatusState(state_val)
            except ValueError:
                pass
        saved_agents = saved.get("agents")
        if isinstance(saved_agents, dict):
            for aid, adata in saved_agents.items():
                if not isinstance(adata, dict):
                    continue
                try:
                    agent_state = StatusState(adata["state"])
                except (KeyError, ValueError):
                    continue
                entry.agents[aid] = _AgentEntry(
                    agent_id=aid,
                    state=agent_state,
                    agent_type=adata.get("agent_type", ""),
                )

    # ------------------------------------------------------------------
    # Window management
    # ------------------------------------------------------------------

    def _toggle_window(self):
        viewable = self._main_window.toplevel.winfo_viewable()
        logger.debug(
            "toggle_window viewable=%s x=%s y=%s h=%s",
            viewable,
            self._main_window.toplevel.winfo_x(),
            self._main_window.toplevel.winfo_y(),
            self._main_window.toplevel.winfo_height(),
        )
        if viewable:
            self._main_window.hide()
        else:
            self._main_window.show()

    def _show_window(self):
        self._main_window.show()

    def _hide_window(self):
        self._main_window.hide()

    def _open_settings(self):
        SettingsWindow(self._root, self._settings, on_save=self._on_settings_save)

    def _on_settings_save(self, new_settings: Settings):
        self._settings = new_settings
        self._save_settings_safe()
        set_run_on_startup(enabled=new_settings.run_on_startup)
        # Remove sessions that now match the ignore regex
        if new_settings.ignore_regex:
            ignored_pids = [
                pid for pid, entry in self._sessions.items() if self._is_ignored(entry.session.cwd)
            ]
            for pid in ignored_pids:
                self._sessions.pop(pid, None)
            if ignored_pids:
                self._save_session_state()
        self._main_window.apply_settings(new_settings)
        self._refresh_ui()
        logger.info("settings saved and applied")

    def _restart(self):
        """Save state, tear down, and re-exec the same process."""
        self._save_window_position()
        self._save_settings_safe()
        self._save_session_state()
        self._hook_server.stop()
        if self._tray_icon:
            self._tray_icon.stop()
        self._root.quit()
        logger.info("restarting dashboard")
        args = build_restart_args()
        try:
            os.execv(sys.executable, args)
        except OSError:
            logger.exception("failed to restart via execv")

    def _quit(self):
        self._save_window_position()
        self._save_settings_safe()
        self._hook_server.stop()
        if self._tray_icon:
            self._tray_icon.stop()
        self._root.quit()

    def _on_position_save(self, x: int, y: int):
        self._settings.window_x = x
        self._settings.window_y = y
        self._save_settings_safe()

    def _on_width_save(self, width: int):
        self._settings.row_width = width
        self._save_settings_safe()

    def _save_settings_safe(self):
        try:
            save_settings(self._settings)
        except OSError as exc:
            logger.error("failed to save settings: %s", exc)

    def _save_window_position(self):
        x, y = self._main_window.get_position()
        if x is not None and y is not None:
            self._settings.window_x = x
            self._settings.window_y = y

    # ------------------------------------------------------------------
    # Tray priority
    # ------------------------------------------------------------------

    def _highest_priority_state(
        self,
        session_states: list[SessionRow],
    ) -> StatusState | None:
        """Pick the highest-priority actionable state for the tray icon.

        Non-actionable states (e.g. Working) are skipped — the tray icon
        should only reflect states where the user can take action.
        """
        if not session_states:
            return None
        best = None
        best_priority = 999
        for row in session_states:
            if row.unattached:
                continue
            state = row.state
            if state not in _ACTIONABLE_STATES:
                continue
            p = _STATE_PRIORITY.get(state, 999)
            if p < best_priority:
                best = state
                best_priority = p
        return best

    def _tray_color_for_state(self, state: StatusState | None) -> tuple[int, int, int]:
        hex_color = self._tray_color_hex_for_state(state)
        return config.hex_to_rgb(hex_color=hex_color)

    def _tray_color_hex_for_state(self, state: StatusState | None) -> str:
        color_map = {
            StatusState.PERMISSION_REQUIRED: self._settings.color_permission_required,
            StatusState.AWAITING_INPUT: self._settings.color_awaiting_input,
            StatusState.READY: self._settings.color_ready,
            StatusState.WORKING: self._settings.color_working,
            StatusState.IDLE: self._settings.color_idle,
        }
        return (
            color_map.get(state, self._settings.color_idle) if state else self._settings.color_idle
        )
